    event: K,
    handler: EventHandler<TEvents[K]>,
  ): void {
    this.handlers.get(event)?.delete(handler);
  }

  emit<K extends keyof TEvents>(event: K, data: TEvents[K]): void {
    this.handlers.get(event)?.forEach((handler) => handler(data));
