type Result<T, E> = Success<T> | Failure<E>;

interface Success<T> {
  ok: true;
  value: T;
}

interface Failure<E> {
  ok: false;
  error: E;
}

function tryParse(json: string): Result<unknown, Error> {
  try {
    return { ok: true, value: JSON.parse(json) };
  } catch (e) {
