    let mut counts = HashMap::new();
    for word in text.split_whitespace() {
        let cleaned: &str = word.trim_matches(|c: char| !c.is_alphanumeric());
        *counts.entry(cleaned).or_insert(0) += 1;
    }
    counts
}
