async function paginate(endpoint,pageSize = 20) {
  let page = 1;
  let hasMore = true;
  while (hasMore) {
    const response = await fetch(
      `${endpoint}?page=${page}&size=${pageSize}`,);
    const data = await response.json();
    if (data.items.length < pageSize) {
      hasMore = false;
    }
    for (const item of data.items) {
      yield item;
    }
    page++;
  }
}
